export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export enum VoiceName {
  Puck = 'Puck',
  Charon = 'Charon',
  Kore = 'Kore',
  Fenrir = 'Fenrir',
  Zephyr = 'Zephyr'
}

export interface LiveSessionConfig {
  voice: VoiceName;
  systemInstruction: string;
}

export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createPcmBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useRef, useEffect } from 'react';

interface VisualizerProps {
  isListening: boolean;
  isModelSpeaking: boolean;
}

export const Visualizer: React.FC<VisualizerProps> = ({ isListening, isModelSpeaking }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationId: number;
    let startTime = Date.now();

    const draw = () => {
      const now = Date.now();
      const elapsed = (now - startTime) / 1000;

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const centerX = canvas.width / 2;
      const centerY = canvas.height / 2;
      const radius = 60;

      // Draw concentric rings based on activity
      const baseAlpha = isListening || isModelSpeaking ? 0.8 : 0.2;
      const color = isModelSpeaking ? 'rgba(56, 189, 248,' : 'rgba(129, 140, 248,';

      for (let i = 0; i < 3; i++) {
        const pulse = Math.sin(elapsed * 4 + i) * 10;
        const currentRadius = radius + (i * 20) + (isListening || isModelSpeaking ? pulse : 0);

        ctx.beginPath();
        ctx.arc(centerX, centerY, currentRadius, 0, Math.PI * 2);
        ctx.strokeStyle = `${color}${baseAlpha / (i + 1)})`;
        ctx.lineWidth = 2;
        ctx.stroke();
      }

      // Draw main center circle
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius - 10, 0, Math.PI * 2);
      ctx.fillStyle = isModelSpeaking ? '#0ea5e9' : (isListening ? '#6366f1' : '#334155');
      ctx.shadowBlur = isListening || isModelSpeaking ? 20 : 0;
      ctx.shadowColor = isModelSpeaking ? '#0ea5e9' : '#6366f1';
      ctx.fill();
      ctx.shadowBlur = 0;

      animationId = requestAnimationFrame(draw);
    };

    draw();
    return () => cancelAnimationFrame(animationId);
  }, [isListening, isModelSpeaking]);

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-slate-900/50 rounded-3xl border border-slate-700/50 backdrop-blur-xl">
      <canvas 
        ref={canvasRef} 
        width={300} 
        height={300} 
        className="max-w-full"
      />
      <div className="mt-4 text-center">
        <p className="text-sm font-medium text-slate-400 uppercase tracking-widest">
          {isModelSpeaking ? 'Gemini is speaking...' : (isListening ? 'Listening...' : 'Ready to talk')}
        </p>
      </div>
    </div>
  );
};

import React, { useRef, useEffect } from 'react';
